<?php namespace App\Domains\RealEstateSales\Services; class SalesService { public function createResidential(array $data) { return \App\Domains\RealEstateSales\Models\ResidentialSale::create($data); } public function createCommercial(array $data) { return \App\Domains\RealEstateSales\Models\CommercialSale::create($data); } public function createLand(array $data) { return \App\Domains\RealEstateSales\Models\LandSale::create($data); } public function createEnterprise(array $data) { return \App\Domains\RealEstateSales\Models\EnterpriseSale::create($data); } }
